8	
9	class EloquentAuditEventRepository implements AuditEventRepositoryInterface
10	{
11	    /**
12	     * Record an audit event.
13	     *
14	     * Idempotency: If a record with the given correlation_id already exists,
15	     * the existing record is returned without creating a duplicate.
16	     *
17	     * CRITICAL: This repository NEVER calls update() or delete().
18	     * The AuditEvent model itself enforces this at the model level as well.
19	     */
20	    public function record(
21	        string $correlationId,
22	        AuditAction $action,
23	        ?string $actorId,
24	        ?string $auditableType,
25	        ?string $auditableId,
26	        ?string $beforeHash,
27	        ?string $afterHash,
28	        array $payload,
29	        string $ipAddress
30	    ): mixed {
31	        // Idempotency check — return existing record without inserting a duplicate.
32	        if ($this->correlationIdExists($correlationId)) {
33	            return AuditEvent::where('correlation_id', $correlationId)->first();
34	        }
35	
36	        $event = new AuditEvent();
37	        $event->correlation_id  = $correlationId;
38	        $event->action          = $action;
39	        $event->actor_id        = $actorId;
40	        $event->auditable_type  = $auditableType;
41	        $event->auditable_id    = $auditableId;
42	        $event->before_hash     = $beforeHash;
43	        $event->after_hash      = $afterHash;
44	        $event->payload         = $payload;
45	        $event->ip_address      = $ipAddress;
46	        $event->created_at      = now();
47	
48	        // save() is overridden on AuditEvent to throw if $this->exists — safe here
49	        // because this is a new (non-persisted) model instance.
50	        $event->save();
51	
52	        return $event;
53	    }
54	
55	    /**
56	     * Whether an audit event with the given correlation_id already exists.
57	     */
58	    public function correlationIdExists(string $correlationId): bool
59	    {
60	        return AuditEvent::where('correlation_id', $correlationId)->exists();
61	    }
62	}
