480	     * Guard that a node is in an actionable state, its instance is not terminal,
481	     * and the acting user is the assigned approver (or holds a supervisory role).
482	     *
483	     * @throws AuthorizationException             If user is not the assigned approver
484	     * @throws WorkflowNodeNotActionableException If node is not in an actionable state
485	     * @throws WorkflowTerminatedException        If the parent instance is already terminal
486	     */
487	    private function guardNodeActionable(WorkflowNode $node, User $user): void
488	    {
489	        // BLOCKER-2: Enforce sequential predecessor ordering — all lower-order nodes must be terminal.
490	        // This prevents out-of-order approval bypasses in multi-step workflows.
491	        $blockedByPredecessor = WorkflowNode::where('workflow_instance_id', $node->workflow_instance_id)
492	            ->where('node_order', '<', $node->node_order)
493	            ->whereNotIn('status', [WorkflowStatus::Approved->value, WorkflowStatus::Rejected->value])
494	            ->exists();
495	
496	        if ($blockedByPredecessor) {
497	            throw new WorkflowNodeNotActionableException('Predecessor nodes must complete before this node can be actioned.');
498	        }
499	
500	        // Unassigned nodes are restricted to supervisors only.
501	        if ($node->assigned_to === null) {
502	            if (!$this->isSupervisor($user)) {
503	                throw new AuthorizationException('This node has no assigned approver. Only managers or admins may act on unassigned nodes.');
504	            }
505	        } elseif ($node->assigned_to !== $user->id && !$this->isSupervisor($user)) {
506	            throw new AuthorizationException('You are not the assigned approver for this workflow node.');
507	        }
508	
509	        if (!$node->status->isActionable()) {
510	            throw new WorkflowNodeNotActionableException();
511	        }
512	
513	        if ($node->instance->status->isTerminal()) {
514	            throw new WorkflowTerminatedException();
515	        }
516	    }
