519	     * Evaluate a conditional node's branch condition against the context data.
520	     *
521	     * Returns true if no condition is configured (unconditional node).
522	     * Supported operators: gt, lt, eq, gte, lte.
523	     */
524	    private function evaluateCondition(WorkflowTemplateNode $node, array $contextData): bool
525	    {
526	        if (empty($node->condition_field)) {
527	            return true;
528	        }
529	
530	        $fieldValue    = $contextData[$node->condition_field] ?? null;
531	        $condValue     = $node->condition_value;
532	        $condOperator  = $node->condition_operator;
533	
534	        if ($fieldValue === null || $condValue === null || $condOperator === null) {
535	            return true;
536	        }
537	
538	        return match ($condOperator) {
539	            'gt'    => $fieldValue > $condValue,
540	            'lt'    => $fieldValue < $condValue,
541	            'eq'    => $fieldValue == $condValue,
542	            'gte'   => $fieldValue >= $condValue,
543	            'lte'   => $fieldValue <= $condValue,
544	            default => true,
545	        };
546	    }
