3	namespace App\Jobs;
4	
5	use App\Application\Logging\StructuredLogger;
6	use App\Models\AttachmentLink;
7	use Illuminate\Bus\Queueable;
8	use Illuminate\Contracts\Queue\ShouldQueue;
9	use Illuminate\Foundation\Bus\Dispatchable;
10	use Illuminate\Queue\InteractsWithQueue;
11	use Illuminate\Queue\SerializesModels;
12	
13	/**
14	 * Prunes expired, consumed, and revoked share links from the database.
15	 *
16	 * Scheduled every 15 minutes.
17	 *
18	 * LAN share-link expiry is enforced at runtime by ExpiryEvaluator::isLinkExpired()
19	 * checking expires_at.isPast(). This job performs offline cleanup — deleting
20	 * records that are no longer usable (expired, consumed, or revoked) and are
21	 * older than the cleanup grace period (24 hours) to allow admin/audit queries
22	 * to see recent terminations before removal.
23	 *
24	 * Audit provenance is maintained in the audit_events table via LinkConsume and
25	 * LinkRevoke actions recorded at resolution/revocation time; physical deletion
26	 * of the link record after the grace period does not break audit continuity.
27	 */
28	class ExpireAttachmentLinksJob implements ShouldQueue
29	{
30	    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
31	
32	    /**
33	     * Grace period after expiry/consumption before physical deletion (hours).
34	     */
35	    private const CLEANUP_GRACE_HOURS = 24;
36	
37	    public function handle(StructuredLogger $logger): void
38	    {
39	        $cutoff = now()->subHours(self::CLEANUP_GRACE_HOURS);
40	
41	        // Expired by TTL
42	        $expiredCount = AttachmentLink::query()
43	            ->where('expires_at', '<', $cutoff)
44	            ->whereNull('revoked_at')
45	            ->whereNull('consumed_at')
46	            ->delete();
47	
48	        // Consumed single-use links
49	        $consumedCount = AttachmentLink::query()
50	            ->whereNotNull('consumed_at')
51	            ->where('consumed_at', '<', $cutoff)
52	            ->delete();
53	
54	        // Revoked links
55	        $revokedCount = AttachmentLink::query()
56	            ->whereNotNull('revoked_at')
57	            ->where('revoked_at', '<', $cutoff)
58	            ->delete();
59	
60	        $total = $expiredCount + $consumedCount + $revokedCount;
61	
62	        if ($total > 0) {
63	            $logger->info('Expired/consumed/revoked attachment links pruned', [
64	                'expired_count'  => $expiredCount,
65	                'consumed_count' => $consumedCount,
66	                'revoked_count'  => $revokedCount,
67	            ], 'maintenance');
68	        }
69	    }
70	}
