15	class BackupMetadataService
16	{
17	    /**
18	     * Create a new backup job record in the pending state.
19	     */
20	    public function startBackup(bool $isManual = false): BackupJob
21	    {
22	        $retentionDays = (int) config('meridian.backup.retention_days', 14);
23	
24	        return BackupJob::create([
25	            'started_at'           => now(),
26	            'status'               => 'pending',
27	            'is_manual'            => $isManual,
28	            'retention_expires_at' => now()->addDays($retentionDays),
29	        ]);
30	    }
31	
32	    /**
33	     * Mark the job as actively running.
34	     */
35	    public function markRunning(string $jobId): void
36	    {
37	        BackupJob::where('id', $jobId)->update(['status' => 'running']);
38	    }
39	
40	    /**
41	     * Mark the job as successfully completed.
42	     *
43	     * @param array $manifest  Structured list of backed-up artifacts
44	     * @param int   $sizeBytes Total size of the backup in bytes
45	     */
46	    public function completeBackup(string $jobId, array $manifest, int $sizeBytes): void
47	    {
48	        BackupJob::where('id', $jobId)->update([
49	            'status'       => 'success',
50	            'manifest'     => $manifest,
51	            'size_bytes'   => $sizeBytes,
52	            'completed_at' => now(),
53	        ]);
54	    }
