60	    {
61	        BackupJob::where('id', $jobId)->update([
62	            'status'        => 'failed',
63	            'error_message' => $error,
64	            'completed_at'  => now(),
65	        ]);
66	    }
67	
68	    /**
69	     * Delete backup job records whose retention window has expired.
70	     *
71	     * HIGH-3: Also deletes the physical backup artifact from local storage
72	     * before removing the DB row, so that physical and metadata retention
73	     * are always consistent (no orphaned encrypted dump files on disk).
74	     *
75	     * @return int Number of metadata rows deleted
76	     */
77	    public function pruneExpired(): int
78	    {
79	        $expiredJobs = BackupJob::where('retention_expires_at', '<', now())
80	            ->get(['id', 'manifest']);
81	
82	        // Delete physical backup artifacts before removing metadata rows
83	        foreach ($expiredJobs as $job) {
84	            $manifest = $job->manifest;
85	            if (is_array($manifest)) {
86	                $dumpFile = $manifest['dump_file'] ?? null;
87	                if ($dumpFile && Storage::disk('local')->exists($dumpFile)) {
88	                    Storage::disk('local')->delete($dumpFile);
89	                }
90	            }
91	        }
92	
93	        return BackupJob::where('retention_expires_at', '<', now())->delete();
94	    }
