5	/**
6	 * Enforces the canary rollout constraints for configuration versions.
7	 *
8	 * Rules (from original prompt):
9	 *   - Canary rollout capped at 10% of eligible target population
10	 *   - Must run for 24 hours before full promotion is allowed
11	 *
12	 * From questions.md (ambiguity #5):
13	 *   - Cap applies to the selected target population type (stores OR users, whichever is chosen)
14	 *
15	 * Immutable value object — no instances.
16	 */
17	final class CanaryConstraint
18	{
19	    /** Maximum percentage of eligible targets that can receive the canary version */
20	    public const MAX_CANARY_PERCENT = 10.0;
21	
22	    /** Minimum hours the canary must run before full promotion is allowed */
23	    public const MIN_PROMOTION_HOURS = 24;
24	
25	    private function __construct() {}
26	
27	    /**
28	     * Compute the maximum number of targets allowed for a canary rollout.
29	     *
30	     * @param int $eligibleCount Total eligible targets in the population
31	     * @return int Maximum target count (floor of eligible * 10%)
32	     */
33	    public static function maxTargets(int $eligibleCount): int
34	    {
35	        return (int) floor($eligibleCount * (self::MAX_CANARY_PERCENT / 100));
36	    }
37	
38	    /**
39	     * Whether the requested target count is within the 10% cap.
40	     *
41	     * @param int $requestedCount Number of targets requested
42	     * @param int $eligibleCount  Total eligible population
43	     */
44	    public static function isWithinCap(int $requestedCount, int $eligibleCount): bool
45	    {
46	        if ($eligibleCount <= 0) {
47	            return false;
48	        }
49	        return $requestedCount <= self::maxTargets($eligibleCount);
50	    }
51	
52	    /**
53	     * Compute the actual percentage for the given selection.
54	     */
55	    public static function computePercent(int $selectedCount, int $eligibleCount): float
56	    {
57	        if ($eligibleCount <= 0) {
58	            return 0.0;
59	        }
60	        return round(($selectedCount / $eligibleCount) * 100, 2);
61	    }
62	
63	    /**
64	     * Whether the canary has been running long enough to allow full promotion.
65	     */
66	    public static function canPromote(\DateTimeImmutable $canaryStartedAt, \DateTimeImmutable $now): bool
67	    {
68	        $minimumDuration = new \DateInterval('PT' . self::MIN_PROMOTION_HOURS . 'H');
69	        $earliestPromotion = $canaryStartedAt->add($minimumDuration);
70	        return $now >= $earliestPromotion;
71	    }
72	
73	    /**
74	     * Compute the earliest timestamp at which full promotion is allowed.
75	     */
76	    public static function earliestPromotionAt(\DateTimeImmutable $canaryStartedAt): \DateTimeImmutable
77	    {
78	        return $canaryStartedAt->modify('+' . self::MIN_PROMOTION_HOURS . ' hours');
79	    }
80	}
