80	    private function instanceShape(WorkflowInstance $instance, bool $withNodes = false): array
81	    {
82	        $shape = [
83	            'id'                   => $instance->id,
84	            'workflow_template_id' => $instance->workflow_template_id,
85	            'record_type'          => $instance->record_type,
86	            'record_id'            => $instance->record_id,
87	            'status'               => $instance->status instanceof \BackedEnum
88	                                        ? $instance->status->value
89	                                        : $instance->status,
90	            'initiated_by'         => $instance->initiated_by,
91	            'started_at'           => $instance->started_at?->toIso8601String(),
92	            'completed_at'         => $instance->completed_at?->toIso8601String(),
93	            'withdrawn_at'         => $instance->withdrawn_at?->toIso8601String(),
94	            'withdrawn_by'         => $instance->withdrawn_by,
95	            'withdrawal_reason'    => $instance->withdrawal_reason,
96	            'created_at'           => $instance->created_at?->toIso8601String(),
97	            'updated_at'           => $instance->updated_at?->toIso8601String(),
98	        ];
99	
100	        if ($withNodes && $instance->relationLoaded('nodes')) {
101	            $shape['nodes'] = $instance->nodes->map(fn($n) => $this->nodeShape($n))->values();
102	        }
103	
104	        return $shape;
105	    }
