113	            'status'           => $node->status instanceof \BackedEnum ? $node->status->value : $node->status,
114	            'assigned_to'      => $node->assigned_to,
115	            'sla_due_at'       => $node->sla_due_at?->toIso8601String(),
116	            'completed_at'     => $node->completed_at?->toIso8601String(),
117	            'label'            => $node->label,
118	        ];
119	
120	        if ($node->relationLoaded('approvals')) {
121	            $shape['approvals'] = $node->approvals->map(fn($a) => [
122	                'id'             => $a->id,
123	                'action'         => $a->action instanceof \BackedEnum ? $a->action->value : $a->action,
124	                'actor_id'       => $a->actor_id,
125	                'reason'         => $a->reason,
126	                'target_user_id' => $a->target_user_id,
127	                'created_at'     => $a->created_at?->toIso8601String(),
128	            ])->values();
129	        }
130	
131	        return $shape;
132	    }
