3	namespace App\Jobs;
4	
5	use App\Application\Logging\StructuredLogger;
6	use App\Domain\Audit\Contracts\AuditEventRepositoryInterface;
7	use App\Domain\Audit\Enums\AuditAction;
8	use App\Models\AttachmentLink;
9	use Illuminate\Bus\Queueable;
10	use Illuminate\Contracts\Queue\ShouldQueue;
11	use Illuminate\Foundation\Bus\Dispatchable;
12	use Illuminate\Queue\InteractsWithQueue;
13	use Illuminate\Queue\SerializesModels;
14	
15	/**
16	 * Prunes expired, consumed, and revoked share links from the database.
17	 *
18	 * Scheduled every 15 minutes.
19	 *
20	 * LAN share-link expiry is enforced at runtime by ExpiryEvaluator::isLinkExpired()
21	 * checking expires_at.isPast(). This job performs offline cleanup — deleting
22	 * records that are no longer usable (expired, consumed, or revoked) and are
23	 * older than the cleanup grace period (24 hours) to allow admin/audit queries
24	 * to see recent terminations before removal.
25	 *
26	 * Audit provenance is maintained in the audit_events table via LinkConsume and
27	 * LinkRevoke actions recorded at resolution/revocation time; physical deletion
28	 * of the link record after the grace period does not break audit continuity.
29	 */
30	class ExpireAttachmentLinksJob implements ShouldQueue
31	{
32	    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
33	
34	    /**
35	     * Grace period after expiry/consumption before physical deletion (hours).
36	     */
37	    private const CLEANUP_GRACE_HOURS = 24;
38	
39	    public function handle(StructuredLogger $logger, AuditEventRepositoryInterface $audit): void
40	    {
41	        $cutoff = now()->subHours(self::CLEANUP_GRACE_HOURS);
42	
43	        // Expired by TTL — no prior audit event exists for these; emit one per link before deletion.
44	        $expiredLinks = AttachmentLink::query()
45	            ->where('expires_at', '<', $cutoff)
46	            ->whereNull('revoked_at')
47	            ->whereNull('consumed_at')
48	            ->get();
49	
50	        $expiredCount = 0;
51	        foreach ($expiredLinks as $link) {
52	            $beforeHash = hash('sha256', json_encode($link->toArray()));
53	            $audit->record(
54	                correlationId: hash('sha256', 'expire_link:' . $link->id),
55	                action:        AuditAction::Delete,
56	                actorId:       null,
57	                auditableType: AttachmentLink::class,
58	                auditableId:   $link->id,
59	                beforeHash:    $beforeHash,
60	                afterHash:     $beforeHash,
61	                payload:       ['reason' => 'ttl_expired'],
62	                ipAddress:     '127.0.0.1',
63	            );
64	            $link->delete();
65	            $expiredCount++;
66	        }
67	
68	        // Consumed single-use links
69	        $consumedCount = AttachmentLink::query()
70	            ->whereNotNull('consumed_at')
71	            ->where('consumed_at', '<', $cutoff)
72	            ->delete();
73	
74	        // Revoked links
75	        $revokedCount = AttachmentLink::query()
76	            ->whereNotNull('revoked_at')
77	            ->where('revoked_at', '<', $cutoff)
78	            ->delete();
79	
80	        $total = $expiredCount + $consumedCount + $revokedCount;
81	
82	        if ($total > 0) {
83	            $logger->info('Expired/consumed/revoked attachment links pruned', [
84	                'expired_count'  => $expiredCount,
85	                'consumed_count' => $consumedCount,
86	                'revoked_count'  => $revokedCount,
87	            ], 'maintenance');
88	        }
89	    }
90	}
