12	
13	/**
14	 * Bulk-transitions active attachments that have passed their validity window to 'expired'.
15	 *
16	 * Scheduled daily. Delegates to AttachmentService::processExpiredAttachments() which
17	 * performs a bulk update on attachments where status='active' AND expires_at < now().
18	 *
19	 * Expired attachments remain in the database for audit and download-history purposes
20	 * but cannot be accessed for new downloads or link generation.
21	 */
22	class ExpireAttachmentsJob implements ShouldQueue
23	{
24	    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
25	
26	    public function handle(AttachmentService $attachments, StructuredLogger $logger): void
27	    {
28	        $transitioned = $attachments->processExpiredAttachments();
29	
30	        if ($transitioned > 0) {
31	            $logger->info('Expired attachments transitioned to expired status', [
32	                'transitioned_count' => $transitioned,
33	            ], 'maintenance');
34	        }
35	    }
36	}
