3	namespace App\Application\Attachment;
4	
5	use App\Domain\Attachment\Contracts\AttachmentRepositoryInterface;
6	use App\Domain\Attachment\Enums\AllowedMimeType;
7	use App\Domain\Attachment\Enums\AttachmentStatus;
8	use App\Domain\Attachment\ValueObjects\FileConstraints;
9	use App\Domain\Attachment\ValueObjects\LinkTtlConstraint;
10	use App\Domain\Audit\Contracts\AuditEventRepositoryInterface;
11	use App\Domain\Audit\Enums\AuditAction;
12	use App\Exceptions\Attachment\AttachmentCapacityExceededException;
13	use App\Exceptions\Attachment\AttachmentExpiredException;
14	use App\Exceptions\Attachment\AttachmentRevokedException;
15	use App\Exceptions\Attachment\DuplicateAttachmentException;
16	use App\Exceptions\Attachment\InvalidMimeTypeException;
17	use App\Exceptions\Attachment\LinkConsumedException;
18	use App\Exceptions\Attachment\LinkExpiredException;
19	use App\Exceptions\Attachment\LinkRevokedException;
20	use App\Infrastructure\Security\EncryptionService;
21	use App\Infrastructure\Security\ExpiryEvaluator;
22	use App\Infrastructure\Security\FingerprintService;
23	use App\Models\Attachment;
24	use App\Models\AttachmentLink;
25	use App\Models\User;
26	use Illuminate\Http\UploadedFile;
27	use Illuminate\Support\Facades\Storage;
28	use Illuminate\Support\Str;
29	use Illuminate\Validation\ValidationException;
30	
31	/**
32	 * Orchestrates attachment and evidence lifecycle operations.
33	 *
34	 * Responsibilities:
35	 *   - Upload files with MIME magic-byte validation, dedup check, encryption, and storage
36	 *   - Create expiring LAN share links with optional single-use and IP restriction
37	 *   - Resolve share links: validate usability, decrypt content, consume if single-use
38	 *   - Revoke attachments (status update + soft delete)
39	 *   - Process expired attachments (batch status transition)
40	 *
41	 * CRITICAL INVARIANTS:
42	 *   - MIME check uses finfo magic bytes (not just Content-Type header)
43	 *   - Fingerprint deduplication is GLOBAL — not scoped to a single record
44	 *   - File content is AES-256-CBC encrypted at rest; path string is ALSO encrypted
45	 *   - consumeLink() uses lockForUpdate() in the repository — concurrent-safe
46	 *   - Link resolution records a LinkConsume audit event for every resolution
47	 */
48	class AttachmentService
49	{
50	    public function __construct(
51	        private readonly AttachmentRepositoryInterface $attachments,
52	        private readonly AuditEventRepositoryInterface $audit,
53	        private readonly EncryptionService $encryption,
54	        private readonly FingerprintService $fingerprint,
55	        private readonly ExpiryEvaluator $expiry,
56	    ) {}
57	
58	    // -------------------------------------------------------------------------
59	    // Upload
60	    // -------------------------------------------------------------------------
61	
62	    /**
63	     * Upload and store an attachment for a business record.
64	     *
65	     * Pipeline:
66	     *   1. finfo magic-bytes MIME check (MIME spoofing prevention)
67	     *   2. Count check: ≤ 20 active attachments per record
68	     *   3. SHA-256 fingerprint + global dedup check
69	     *   4. AES-256-CBC encrypt file content in memory
70	     *   5. Write encrypted JSON envelope to storage/app/attachments/{year}/{month}/{uuid}.enc
71	     *   6. Encrypt the path string for DB storage
72	     *   7. Create Attachment record with computed expires_at
73	     *
74	     * @param string   $recordType Fully-qualified model class name (e.g. 'App\Models\Document')
75	     * @param string   $recordId   UUID of the associated business record
76	     * @param int|null $validityDays Validity override; falls back to config default (365)
77	     *
78	     * @throws ValidationException                  If MIME type is not permitted
79	     * @throws AttachmentCapacityExceededException  If record already has 20 attachments
80	     * @throws DuplicateAttachmentException         If SHA-256 fingerprint already exists globally
81	     */
82	    public function upload(
83	        User $user,
84	        string $recordType,
85	        string $recordId,
86	        UploadedFile $file,
87	        ?int $validityDays,
88	        string $ipAddress
89	    ): Attachment {
90	        // 1. Magic-bytes MIME check — prevents spoofing beyond Laravel's declared-type validation
91	        $finfo        = new \finfo(FILEINFO_MIME_TYPE);
92	        $detectedMime = $finfo->file($file->getRealPath());
93	        $declaredMime = $file->getClientMimeType();
94	
95	        if (!is_string($detectedMime) || $detectedMime === '') {
96	            throw ValidationException::withMessages([
97	                'file' => ['Unable to determine uploaded file MIME type.'],
98	            ]);
99	        }
100	
101	        // Enforce strict declared-vs-detected consistency for evidence uploads.
102	        if (is_string($declaredMime)
103	            && $declaredMime !== ''
104	            && strtolower($declaredMime) !== strtolower($detectedMime)
105	        ) {
106	            throw new InvalidMimeTypeException($declaredMime, $detectedMime);
107	        }
108	
109	        if (!AllowedMimeType::tryFromMime($detectedMime)) {
110	            throw ValidationException::withMessages([
111	                'file' => ['File type not permitted by server-side MIME inspection.'],
112	            ]);
113	        }
114	
115	        // 2. Count check — fail fast before expensive fingerprint and encryption operations
116	        $count = $this->attachments->countActiveForRecord($recordType, $recordId);
117	
118	        if (FileConstraints::wouldExceedFileCount($count)) {
119	            throw new AttachmentCapacityExceededException(FileConstraints::MAX_FILES_PER_RECORD);
120	        }
121	
122	        // 3. SHA-256 fingerprint + global dedup
123	        $sha256 = $this->fingerprint->computeFromPath($file->getRealPath());
124	
125	        if ($this->attachments->fingerprintExists($sha256)) {
126	            throw new DuplicateAttachmentException($sha256);
127	        }
128	
129	        // 4. Encrypt file content in memory
130	        $plaintext = file_get_contents($file->getRealPath());
131	        $encrypted = $this->encryption->encrypt($plaintext);
132	
133	        // 5. Write encrypted JSON envelope: {"ciphertext":"...","iv":"...","key_id":"v1"}
134	        $year         = now()->format('Y');
135	        $month        = now()->format('m');
136	        $uuid         = Str::uuid()->toString();
137	        $relativePath = "attachments/{$year}/{$month}/{$uuid}.enc";
138	
139	        Storage::disk('local')->put($relativePath, json_encode($encrypted));
140	
141	        // 6. Encrypt the storage path string for DB storage
142	        $encryptedPath = json_encode($this->encryption->encrypt($relativePath));
143	
144	        // 7. Compute validity and create DB record
145	        $days      = $validityDays ?? (int) config('meridian.attachments.default_validity_days', 365);
146	        $expiresAt = now()->addDays($days);
147	
148	        $attachment = Attachment::create([
149	            'record_type'        => $recordType,
150	            'record_id'          => $recordId,
151	            'original_filename'  => $file->getClientOriginalName(),
152	            'mime_type'          => $detectedMime,
153	            'file_size_bytes'    => $file->getSize(),
154	            'sha256_fingerprint' => $sha256,
155	            'encrypted_path'     => $encryptedPath,
156	            'encryption_key_id'  => $this->encryption->getActiveKeyId(),
157	            'status'             => AttachmentStatus::Active->value,
158	            'validity_days'      => $days,
159	            'expires_at'         => $expiresAt,
160	            'uploaded_by'        => $user->id,
161	            'department_id'      => $user->department_id,
162	        ]);
163	
164	        $afterHash = hash('sha256', json_encode($attachment->toArray()));
165	        $this->recordAudit(AuditAction::Create, $user->id, Attachment::class, $attachment->id, $ipAddress, afterHash: $afterHash);
166	
167	        return $attachment;
168	    }
169	
170	    // -------------------------------------------------------------------------
171	    // Share Links
172	    // -------------------------------------------------------------------------
173	
174	    /**
175	     * Generate a LAN share link for an active attachment.
176	     *
177	     * @param int    $ttlHours     Requested TTL in hours (clamped to 72 if out of range)
178	     * @param bool   $isSingleUse  Whether the link should be consumed on first resolution
179	     * @param string|null $ipRestriction Optional IP address restriction
180	     *
181	     * @throws AttachmentExpiredException  If the attachment has passed its validity window
182	     * @throws AttachmentRevokedException  If the attachment has been revoked or is not active
183	     */
184	    public function createLink(
185	        User $user,
186	        Attachment $attachment,
187	        int $ttlHours,
188	        bool $isSingleUse,
189	        ?string $ipRestriction,
190	        string $ipAddress
191	    ): AttachmentLink {
192	        if ($this->expiry->isAttachmentExpired($attachment)) {
193	            throw new AttachmentExpiredException();
194	        }
195	
196	        if ($attachment->status !== AttachmentStatus::Active) {
197	            throw new AttachmentRevokedException();
198	        }
199	
200	        // Clamp TTL defensively (form validation should already enforce this)
201	        if (!LinkTtlConstraint::isTtlAllowed($ttlHours)) {
202	            $ttlHours = LinkTtlConstraint::clampTtl($ttlHours);
203	        }
204	
205	        $token = bin2hex(random_bytes(32)); // 64 hex characters
206	
207	        $link = AttachmentLink::create([
208	            'attachment_id'  => $attachment->id,
209	            'token'          => $token,
210	            'expires_at'     => now()->addHours($ttlHours),
211	            'is_single_use'  => $isSingleUse,
212	            'created_by'     => $user->id,
213	            'ip_restriction' => $ipRestriction,
214	        ]);
215	
216	        $this->recordAudit(AuditAction::LinkCreate, $user->id, AttachmentLink::class, $link->id, $ipAddress);
217	
218	        return $link;
219	    }
220	
221	    /**
222	     * Resolve a LAN share link and return decrypted file content.
223	     *
224	     * Validates usability (expiry, revocation, consumption), decrypts the attachment,
225	     * and for single-use links atomically marks it consumed. Always records a
226	     * LinkConsume audit event for traceability.
227	     *
228	     * @return array{content: string, mime_type: string, filename: string}
229	     *
230	     * @throws LinkExpiredException        If the link has passed its TTL
231	     * @throws LinkRevokedException        If the link was administratively revoked
232	     * @throws LinkConsumedException       If a single-use link was already consumed
233	     * @throws AttachmentExpiredException  If the underlying attachment has expired
234	     * @throws AttachmentRevokedException  If the underlying attachment was revoked
235	     */
236	    public function resolveLink(
237	        string $token,
238	        string $requestIp,
239	        ?string $resolverUserId = null,
240	        ?string $resolverUserAgent = null,
241	    ): array
242	    {
243	        $link = $this->attachments->findLinkByToken($token);
244	
245	        if ($link === null) {
246	            abort(404, 'Share link not found.');
247	        }
248	
249	        // Usability checks — order matters: check expiry before revocation before consumption
250	        if ($this->expiry->isLinkExpired($link)) {
251	            throw new LinkExpiredException();
252	        }
253	
254	        if ($this->expiry->isLinkRevoked($link)) {
255	            throw new LinkRevokedException();
256	        }
257	
258	        if ($this->expiry->isLinkConsumed($link)) {
259	            throw new LinkConsumedException();
260	        }
261	
262	        // Optional IP restriction enforcement
263	        if ($link->ip_restriction !== null && $link->ip_restriction !== $requestIp) {
264	            abort(403, 'IP address not permitted for this link.');
265	        }
266	
267	        $attachment = $link->attachment;
268	
269	        if ($this->expiry->isAttachmentExpired($attachment)) {
270	            throw new AttachmentExpiredException();
271	        }
272	
273	        if ($attachment->status === AttachmentStatus::Revoked) {
274	            throw new AttachmentRevokedException();
275	        }
276	
277	        // HIGH-1: Atomically consume single-use links BEFORE decrypting/serving content.
278	        // consumeLink() uses SELECT FOR UPDATE in a transaction — concurrent-safe.
279	        // If consumption fails (race loser: already consumed by a concurrent request), throw
280	        // immediately before any content is served, ensuring fail-closed single-use semantics.
281	        if ($link->is_single_use) {
282	            $consumed = $this->attachments->consumeLink($link->id, $resolverUserId);
283	            if (!$consumed) {
284	                throw new LinkConsumedException();
285	            }
286	        }
287	
288	        // Decrypt path → read encrypted file envelope → decrypt content
289	        $pathData     = json_decode($attachment->encrypted_path, true);
290	        $relativePath = $this->encryption->decrypt(
291	            $pathData['ciphertext'],
292	            $pathData['iv'],
293	            $pathData['key_id']
294	        );
295	
296	        $fileEnvelope = json_decode(Storage::disk('local')->get($relativePath), true);
297	        $plaintext    = $this->encryption->decrypt(
298	            $fileEnvelope['ciphertext'],
299	            $fileEnvelope['iv'],
300	            $fileEnvelope['key_id']
301	        );
302	
303	        // Record a LinkConsume audit event for every resolution (not just single-use)
304	        $this->recordAudit(
305	            AuditAction::LinkConsume,
306	            $resolverUserId,
307	            AttachmentLink::class,
308	            $link->id,
309	            $requestIp,
310	            payload: [
311	                'resolver_user_agent' => $resolverUserAgent,
312	                'resolved_via'        => $resolverUserId !== null ? 'authenticated' : 'token_only',
313	            ],
314	        );
315	
316	        return [
317	            'content'   => $plaintext,
318	            'mime_type' => $attachment->mime_type,
319	            'filename'  => $attachment->original_filename,
320	        ];
321	    }
322	
323	    // -------------------------------------------------------------------------
324	    // Revocation and Expiry Processing
325	    // -------------------------------------------------------------------------
326	
327	    /**
328	     * Revoke an attachment: update status to revoked and soft-delete the record.
329	     */
330	    public function revokeAttachment(User $user, Attachment $attachment, string $ipAddress): void
331	    {
332	        $beforeHash = hash('sha256', json_encode($attachment->toArray()));
333	        $attachment->update(['status' => AttachmentStatus::Revoked->value]);
334	        $afterHash  = hash('sha256', json_encode($attachment->refresh()->toArray())); // after status update, before soft-delete
335	        $attachment->delete(); // soft-delete
336	
337	        $this->recordAudit(AuditAction::Delete, $user->id, Attachment::class, $attachment->id, $ipAddress, beforeHash: $beforeHash, afterHash: $afterHash);
338	    }
339	
340	    /**
341	     * Batch-transition active attachments that have passed their validity window to 'expired'.
342	     *
343	     * Returns the number of attachments transitioned.
344	     */
345	    public function processExpiredAttachments(): int
346	    {
347	        $attachments = Attachment::where('status', AttachmentStatus::Active->value)
348	            ->whereNotNull('expires_at')
349	            ->where('expires_at', '<', now())
350	            ->get();
351	
352	        foreach ($attachments as $attachment) {
353	            $beforeHash = hash('sha256', json_encode($attachment->toArray()));
354	            $attachment->update(['status' => AttachmentStatus::Expired->value]);
355	            $afterHash  = hash('sha256', json_encode($attachment->refresh()->toArray()));
356	
357	            $this->recordAudit(
358	                AuditAction::Update,
359	                null,
360	                Attachment::class,
361	                $attachment->id,
362	                '127.0.0.1',
363	                payload:    ['reason' => 'validity_window_expired'],
364	                beforeHash: $beforeHash,
365	                afterHash:  $afterHash,
366	            );
367	        }
368	
369	        return count($attachments);
370	    }
371	
372	    // -------------------------------------------------------------------------
373	    // Private helpers
374	    // -------------------------------------------------------------------------
375	
376	    private function recordAudit(
377	        AuditAction $action,
378	        ?string $actorId,
379	        string $auditableType,
380	        string $auditableId,
381	        string $ipAddress,
382	        array $payload = [],
383	        ?string $beforeHash = null,
384	        ?string $afterHash = null,
385	    ): void {
386	        $idempotencyKey = request()->header('X-Idempotency-Key');
387	        $correlationId  = $idempotencyKey !== null
388	            ? hash('sha256', $idempotencyKey . ':' . $auditableId . ':' . $action->value)
389	            : (string) Str::uuid();
390	
391	        $this->audit->record(
392	            correlationId:  $correlationId,
393	            action:         $action,
394	            actorId:        $actorId,
395	            auditableType:  $auditableType,
396	            auditableId:    $auditableId,
397	            beforeHash:     $beforeHash,
398	            afterHash:      $afterHash,
399	            payload:        $payload,
400	            ipAddress:      $ipAddress,
401	        );
402	    }
403	}
