3	namespace App\Http\Controllers\Api;
4	
5	use App\Application\Attachment\AttachmentService;
6	use App\Domain\Attachment\ValueObjects\FileConstraints;
7	use App\Exceptions\Attachment\AttachmentCapacityExceededException;
8	use App\Http\Controllers\Controller;
9	use App\Http\Requests\Attachment\StoreAttachmentRequest;
10	use App\Models\Attachment;
11	use App\Models\Document;
12	use App\Models\ReturnRecord;
13	use App\Models\SalesDocument;
14	use Illuminate\Http\JsonResponse;
15	use Illuminate\Http\Request;
16	use Illuminate\Http\Response;
17	use Illuminate\Support\Facades\DB;
18	
19	class AttachmentController extends Controller
20	{
21	    /**
22	     * Map of URL-friendly type slugs to fully-qualified model class names.
23	     * Used to resolve the polymorphic record_type from the route parameter.
24	     */
25	    private const MORPH_MAP = [
26	        'document'       => Document::class,
27	        'sales_document' => SalesDocument::class,
28	        'return'         => ReturnRecord::class,
29	    ];
30	
31	    public function __construct(
32	        private readonly AttachmentService $service,
33	    ) {}
34	
35	    /**
36	     * GET /api/v1/records/{type}/{id}/attachments
37	     *
38	     * List active attachments for a business record.
39	     *
40	     * Authorization is delegated to the parent record's own policy so that
41	     * department isolation and access_control_scope rules are respected. A user
42	     * who cannot view the parent record cannot list its attachments.
43	     */
44	    public function index(Request $request, string $type, string $id): JsonResponse
45	    {
46	        $recordType = $this->resolveRecordType($type);
47	
48	        // Load the parent record and authorize via its own policy (enforces department scope)
49	        $record = $recordType::findOrFail($id);
50	        $this->authorize('view', $record);
51	
52	        $attachments = Attachment::where('record_type', $recordType)
53	            ->where('record_id', $id)
54	            ->whereNull('deleted_at')
55	            ->orderBy('created_at', 'desc')
56	            ->get();
57	
58	        return response()->json([
59	            'data' => $attachments->map(fn(Attachment $a) => $this->attachmentShape($a)),
60	        ]);
61	    }
62	
63	    /**
64	     * POST /api/v1/records/{type}/{id}/attachments
65	     *
66	     * Upload one or more attachments to a business record.
67	     * Parent record is loaded and authorized via its own policy (department scope).
68	     * Batch cap is pre-checked before processing any files.
69	     */
70	    public function store(StoreAttachmentRequest $request, string $type, string $id): JsonResponse
71	    {
72	        $recordType = $this->resolveRecordType($type);
73	
74	        // Load the parent record and enforce its own policy (department scope)
75	        $record = $recordType::findOrFail($id);
76	        $this->authorize('view', $record);
77	
78	        $files        = $request->file('files');
79	        $validityDays = $request->has('validity_days') ? (int) $request->input('validity_days') : null;
80	
81	        $results = DB::transaction(function () use ($recordType, $id, $record, $files, $request, $validityDays): array {
82	            // Serialize uploads per parent record so concurrent requests cannot overrun the cap.
83	            $recordType::query()
84	                ->whereKey($record->getKey())
85	                ->lockForUpdate()
86	                ->firstOrFail();
87	
88	            $existingCount = Attachment::where('record_type', $recordType)
89	                ->where('record_id', $id)
90	                ->whereNull('deleted_at')
91	                ->lockForUpdate()
92	                ->count();
93	
94	            if ($existingCount + count($files) > FileConstraints::MAX_FILES_PER_RECORD) {
95	                throw new AttachmentCapacityExceededException(FileConstraints::MAX_FILES_PER_RECORD);
96	            }
97	
98	            $uploaded = [];
99	            foreach ($files as $file) {
100	                $attachment = $this->service->upload(
101	                    $request->user(),
102	                    $recordType,
103	                    $id,
104	                    $file,
105	                    $validityDays,
106	                    $request->ip()
107	                );
108	                $uploaded[] = $this->attachmentShape($attachment);
109	            }
110	
111	            return $uploaded;
112	        });
113	
114	        return response()->json(['data' => $results], 201);
115	    }
116	
117	    /**
118	     * GET /api/v1/attachments/{attachment}
119	     *
120	     * Show metadata for a single attachment.
121	     */
122	    public function show(Request $request, Attachment $attachment): JsonResponse
123	    {
124	        $this->authorize('view', $attachment);
125	
126	        return response()->json(['data' => $this->attachmentShape($attachment)]);
127	    }
128	
129	    /**
130	     * DELETE /api/v1/attachments/{attachment}
131	     *
132	     * Revoke an attachment (soft-delete, status set to revoked).
133	     */
134	    public function destroy(Request $request, Attachment $attachment): Response
135	    {
136	        $this->authorize('delete', $attachment);
137	
138	        $this->service->revokeAttachment($request->user(), $attachment, $request->ip());
139	
140	        return response()->noContent();
141	    }
142	
143	    // -------------------------------------------------------------------------
144	    // Private helpers
145	    // -------------------------------------------------------------------------
146	
147	    /**
148	     * Resolve a URL slug to a fully-qualified model class name.
149	     * Returns 422 if the type is not in the morph map.
150	     */
151	    private function resolveRecordType(string $type): string
152	    {
153	        if (!isset(self::MORPH_MAP[$type])) {
154	            abort(422, "Unknown record type '{$type}'. Allowed: " . implode(', ', array_keys(self::MORPH_MAP)));
155	        }
156	
157	        return self::MORPH_MAP[$type];
158	    }
159	
160	    private function attachmentShape(Attachment $attachment): array
161	    {
162	        return [
163	            'id'                 => $attachment->id,
164	            'record_type'        => $attachment->record_type,
165	            'record_id'          => $attachment->record_id,
166	            'original_filename'  => $attachment->original_filename,
167	            'mime_type'          => $attachment->mime_type,
168	            'file_size_bytes'    => $attachment->file_size_bytes,
169	            'sha256_fingerprint' => $attachment->sha256_fingerprint,
170	            'status'             => $attachment->status instanceof \BackedEnum
171	                ? $attachment->status->value
172	                : $attachment->status,
173	            'validity_days'      => $attachment->validity_days,
174	            'expires_at'         => $attachment->expires_at?->toIso8601String(),
175	            'uploaded_by'        => $attachment->uploaded_by,
176	            'department_id'      => $attachment->department_id,
177	            'created_at'         => $attachment->created_at?->toIso8601String(),
178	        ];
179	    }
180	}
