9	
10	class AuditEvent extends Model
11	{
12	    use HasUuids;
13	
14	    public $incrementing = false;
15	
16	    protected $keyType = 'string';
17	
18	    /**
19	     * CRITICAL: audit_events is append-only.
20	     * Only created_at exists — no updated_at column in the schema.
21	     */
22	    const UPDATED_AT = null;
23	
24	    /**
25	     * Disable automatic timestamp management entirely; created_at is set manually.
26	     */
27	    public $timestamps = false;
28	
29	    protected $fillable = [
30	        'id',
31	        'correlation_id',
32	        'actor_id',
33	        'action',
34	        'auditable_type',
35	        'auditable_id',
36	        'before_hash',
37	        'after_hash',
38	        'payload',
39	        'ip_address',
40	        'created_at',
41	    ];
42	
43	    protected function casts(): array
44	    {
45	        return [
46	            'action'     => AuditAction::class,
47	            'payload'    => 'array',
48	            'created_at' => 'datetime',
49	        ];
50	    }
51	
52	    // -------------------------------------------------------------------------
53	    // Append-only enforcement
54	    // -------------------------------------------------------------------------
55	
56	    /**
57	     * Prevent any update to an existing audit event.
58	     */
59	    public function save(array $options = []): bool
60	    {
61	        if ($this->exists) {
62	            throw new \LogicException('AuditEvent records are append-only and cannot be updated.');
63	        }
64	
65	        // Set created_at manually on first insert
66	        if (empty($this->created_at)) {
67	            $this->created_at = now();
68	        }
69	
70	        return parent::save($options);
71	    }
72	
73	    /**
74	     * Prevent soft or hard deletion of audit events.
75	     */
76	    public function delete(): ?bool
77	    {
78	        throw new \LogicException('AuditEvent records are append-only and cannot be deleted.');
79	    }
80	
81	    /**
82	     * Prevent force-deletion of audit events.
83	     */
84	    public function forceDelete(): ?bool
85	    {
86	        throw new \LogicException('AuditEvent records are append-only and cannot be deleted.');
87	    }
88	
89	    // -------------------------------------------------------------------------
90	    // Relations
91	    // -------------------------------------------------------------------------
92	
93	    public function actor(): BelongsTo
94	    {
95	        return $this->belongsTo(User::class, 'actor_id');
