3	namespace App\Application\Backup;
4	
5	use App\Domain\Audit\Contracts\AuditEventRepositoryInterface;
6	use App\Domain\Audit\Enums\AuditAction;
7	use App\Models\BackupJob;
8	use Illuminate\Support\Facades\Storage;
9	
10	/**
11	 * Manages backup job lifecycle metadata in the backup_jobs table.
12	 *
13	 * This service tracks the state of backup operations but does NOT perform
14	 * the actual backup itself — that is the responsibility of a scheduled
15	 * Artisan command or queue job (implemented in a later prompt).
16	 */
17	class BackupMetadataService
18	{
19	    public function __construct(
20	        private readonly AuditEventRepositoryInterface $audit,
21	    ) {}
22	
23	    /**
24	     * Create a new backup job record in the pending state.
25	     */
26	    public function startBackup(bool $isManual = false): BackupJob
27	    {
28	        $retentionDays = (int) config('meridian.backup.retention_days', 14);
29	
30	        return BackupJob::create([
31	            'started_at'           => now(),
32	            'status'               => 'pending',
33	            'is_manual'            => $isManual,
34	            'retention_expires_at' => now()->addDays($retentionDays),
35	        ]);
36	    }
37	
38	    /**
39	     * Mark the job as actively running.
40	     */
41	    public function markRunning(string $jobId): void
42	    {
43	        $job        = BackupJob::findOrFail($jobId);
44	        $beforeHash = hash('sha256', json_encode($job->toArray()));
45	        $job->update(['status' => 'running']);
46	        $afterHash  = hash('sha256', json_encode($job->refresh()->toArray()));
47	
48	        $this->audit->record(
49	            correlationId: hash('sha256', 'backup_running:' . $jobId),
50	            action:        AuditAction::Update,
51	            actorId:       null,
52	            auditableType: BackupJob::class,
53	            auditableId:   $jobId,
54	            beforeHash:    $beforeHash,
55	            afterHash:     $afterHash,
56	            payload:       ['status_transition' => 'pending_to_running'],
57	            ipAddress:     '127.0.0.1',
58	        );
59	    }
60	
61	    /**
62	     * Mark the job as successfully completed.
63	     *
64	     * @param array $manifest  Structured list of backed-up artifacts
65	     * @param int   $sizeBytes Total size of the backup in bytes
66	     */
67	    public function completeBackup(string $jobId, array $manifest, int $sizeBytes): void
68	    {
69	        $job        = BackupJob::findOrFail($jobId);
70	        $beforeHash = hash('sha256', json_encode($job->toArray()));
71	        $job->update([
72	            'status'       => 'success',
73	            'manifest'     => $manifest,
74	            'size_bytes'   => $sizeBytes,
75	            'completed_at' => now(),
76	        ]);
77	        $afterHash = hash('sha256', json_encode($job->refresh()->toArray()));
78	
79	        $this->audit->record(
80	            correlationId: hash('sha256', 'backup_complete:' . $jobId),
81	            action:        AuditAction::Update,
82	            actorId:       null,
83	            auditableType: BackupJob::class,
84	            auditableId:   $jobId,
85	            beforeHash:    $beforeHash,
86	            afterHash:     $afterHash,
87	            payload:       ['status_transition' => 'running_to_success', 'size_bytes' => $sizeBytes],
88	            ipAddress:     '127.0.0.1',
89	        );
90	    }
91	
92	    /**
93	     * Mark the job as failed with an error message.
94	     */
95	    public function failBackup(string $jobId, string $error): void
96	    {
97	        $job        = BackupJob::findOrFail($jobId);
98	        $beforeHash = hash('sha256', json_encode($job->toArray()));
99	        $job->update([
100	            'status'        => 'failed',
101	            'error_message' => $error,
102	            'completed_at'  => now(),
103	        ]);
104	        $afterHash = hash('sha256', json_encode($job->refresh()->toArray()));
105	
106	        $this->audit->record(
107	            correlationId: hash('sha256', 'backup_failed:' . $jobId),
108	            action:        AuditAction::Update,
109	            actorId:       null,
110	            auditableType: BackupJob::class,
111	            auditableId:   $jobId,
112	            beforeHash:    $beforeHash,
113	            afterHash:     $afterHash,
114	            payload:       ['status_transition' => 'running_to_failed'],
115	            ipAddress:     '127.0.0.1',
116	        );
117	    }
118	
119	    /**
120	     * Delete backup job records whose retention window has expired.
121	     *
122	     * HIGH-3: Also deletes the physical backup artifact from local storage
123	     * before removing the DB row, so that physical and metadata retention
124	     * are always consistent (no orphaned encrypted dump files on disk).
125	     *
126	     * @return int Number of metadata rows deleted
127	     */
128	    public function pruneExpired(): int
129	    {
130	        $expiredJobs = BackupJob::where('retention_expires_at', '<', now())->get();
131	
132	        $deletedCount = 0;
133	        foreach ($expiredJobs as $job) {
134	            // Delete physical backup artifact before removing metadata row
135	            $manifest = $job->manifest;
136	            if (is_array($manifest)) {
137	                $dumpFile = $manifest['dump_file'] ?? null;
138	                if ($dumpFile && Storage::disk('local')->exists($dumpFile)) {
139	                    Storage::disk('local')->delete($dumpFile);
140	                }
141	            }
142	
143	            $beforeHash = hash('sha256', json_encode($job->toArray()));
144	
145	            $this->audit->record(
146	                correlationId: hash('sha256', 'backup_prune:' . $job->id),
147	                action:        AuditAction::Delete,
148	                actorId:       null,
149	                auditableType: BackupJob::class,
150	                auditableId:   $job->id,
151	                beforeHash:    $beforeHash,
152	                afterHash:     $beforeHash,
153	                payload:       ['reason' => 'retention_expired'],
154	                ipAddress:     '127.0.0.1',
155	            );
156	
157	            $job->delete();
158	            $deletedCount++;
159	        }
160	
161	        return $deletedCount;
162	    }
163	}
