3	namespace App\Http\Controllers\Api\Admin;
4	
5	use App\Application\Backup\BackupMetadataService;
6	use App\Http\Controllers\Controller;
7	use App\Jobs\RunBackupJob;
8	use App\Models\BackupJob;
9	use Illuminate\Http\JsonResponse;
10	use Illuminate\Http\Request;
11	
12	/**
13	 * Admin endpoint for backup history and manual backup triggers.
14	 *
15	 * Authorization: admin role only.
16	 */
17	class BackupController extends Controller
18	{
19	    public function __construct(
20	        private readonly BackupMetadataService $metadata,
21	    ) {}
22	
23	    /**
24	     * GET /api/v1/admin/backups
25	     *
26	     * List backup history ordered by started_at DESC, with retention status.
27	     *
28	     * Query params:
29	     *   - status    Filter by status: pending | running | success | failed
30	     *   - per_page  Items per page (1–100, default 25)
31	     */
32	    public function index(Request $request): JsonResponse
33	    {
34	        if (!$request->user()->hasRole('admin')) {
35	            abort(403, 'Admin role required to view backup history.');
36	        }
37	
38	        $query = BackupJob::query();
39	
40	        if ($request->has('status')) {
41	            $query->where('status', $request->input('status'));
42	        }
43	
44	        $perPage   = min((int) $request->input('per_page', 25), 100);
45	        $paginated = $query->orderBy('started_at', 'desc')->paginate($perPage);
46	
47	        return response()->json([
48	            'data' => $paginated->map(fn(BackupJob $job) => $this->jobShape($job)),
49	            'meta' => [
50	                'retention_days' => (int) config('meridian.backup.retention_days', 14),
51	                'pagination'     => [
52	                    'current_page' => $paginated->currentPage(),
53	                    'per_page'     => $paginated->perPage(),
54	                    'total'        => $paginated->total(),
55	                    'last_page'    => $paginated->lastPage(),
56	                ],
57	            ],
58	        ]);
59	    }
60	
61	    /**
62	     * POST /api/v1/admin/backups
63	     *
64	     * Trigger an immediate manual backup.
65	     *
66	     * The job is dispatched to the queue synchronously so the response carries
67	     * the created BackupJob record. The actual manifest completion happens
68	     * within the queued job.
69	     */
70	    public function store(Request $request): JsonResponse
71	    {
72	        if (!$request->user()->hasRole('admin')) {
73	            abort(403, 'Admin role required to trigger backups.');
74	        }
75	
76	        RunBackupJob::dispatch(true); // isManual = true
77	
78	        // Return the most recent backup job started in the last few seconds
79	        $job = BackupJob::query()
80	            ->where('is_manual', true)
81	            ->orderBy('started_at', 'desc')
82	            ->first();
83	
84	        if ($job === null) {
85	            // Queue is asynchronous — job not yet processed; return 202 Accepted
86	            return response()->json([
87	                'data'    => null,
88	                'message' => 'Backup job queued. Check backup history shortly.',
89	            ], 202);
90	        }
91	
92	        return response()->json(['data' => $this->jobShape($job)], 202);
93	    }
94	
95	    // -------------------------------------------------------------------------
96	    // Private helpers
97	    // -------------------------------------------------------------------------
98	
99	    private function jobShape(BackupJob $job): array
100	    {
101	        return [
102	            'id'                   => $job->id,
103	            'status'               => $job->status,
104	            'is_manual'            => $job->is_manual,
105	            'started_at'           => $job->started_at?->toIso8601String(),
106	            'completed_at'         => $job->completed_at?->toIso8601String(),
107	            'size_bytes'           => $job->size_bytes,
108	            'manifest'             => $job->manifest,
109	            'error_message'        => $job->error_message,
110	            'retention_expires_at' => $job->retention_expires_at?->toIso8601String(),
111	            'created_at'           => $job->created_at?->toIso8601String(),
112	        ];
113	    }
114	}
