3	namespace App\Domain\Configuration\ValueObjects;
4	
5	/**
6	 * Enforces the canary rollout constraints for configuration versions.
7	 *
8	 * Rules (from original prompt):
9	 *   - Canary rollout capped at 10% of eligible target population
10	 *   - Must run for 24 hours before full promotion is allowed
11	 *
12	 * From questions.md (ambiguity #5):
13	 *   - Cap applies to the selected target population type (stores OR users, whichever is chosen)
14	 *
15	 * Immutable value object — no instances.
16	 */
17	final class CanaryConstraint
18	{
19	    private const DEFAULT_MAX_CANARY_PERCENT = 10.0;
20	    private const DEFAULT_MIN_PROMOTION_HOURS = 24;
21	
22	    private function __construct() {}
23	
24	    /**
25	     * Maximum percentage of eligible targets for canary rollout (resolved from config).
26	     */
27	    public static function maxCanaryPercent(): float
28	    {
29	        return (float) config('meridian.canary.max_percent', self::DEFAULT_MAX_CANARY_PERCENT);
30	    }
31	
32	    /**
33	     * Minimum hours a canary must run before full promotion is allowed (resolved from config).
34	     */
35	    public static function minPromotionHours(): int
36	    {
37	        return (int) config('meridian.canary.min_promotion_hours', self::DEFAULT_MIN_PROMOTION_HOURS);
38	    }
39	
40	    /**
41	     * Compute the maximum number of targets allowed for a canary rollout.
42	     *
43	     * @param int $eligibleCount Total eligible targets in the population
44	     * @return int Maximum target count (floor of eligible * configured percent)
45	     */
46	    public static function maxTargets(int $eligibleCount): int
47	    {
48	        return (int) floor($eligibleCount * (self::maxCanaryPercent() / 100));
49	    }
50	
51	    /**
52	     * Whether the requested target count is within the 10% cap.
53	     *
54	     * @param int $requestedCount Number of targets requested
55	     * @param int $eligibleCount  Total eligible population
56	     */
57	    public static function isWithinCap(int $requestedCount, int $eligibleCount): bool
58	    {
59	        if ($eligibleCount <= 0) {
60	            return false;
61	        }
62	        return $requestedCount <= self::maxTargets($eligibleCount);
63	    }
64	
65	    /**
66	     * Compute the actual percentage for the given selection.
67	     */
68	    public static function computePercent(int $selectedCount, int $eligibleCount): float
69	    {
70	        if ($eligibleCount <= 0) {
71	            return 0.0;
72	        }
73	        return round(($selectedCount / $eligibleCount) * 100, 2);
74	    }
75	
76	    /**
77	     * Whether the canary has been running long enough to allow full promotion.
78	     */
79	    public static function canPromote(\DateTimeImmutable $canaryStartedAt, \DateTimeImmutable $now): bool
80	    {
81	        $minimumDuration = new \DateInterval('PT' . self::minPromotionHours() . 'H');
82	        $earliestPromotion = $canaryStartedAt->add($minimumDuration);
83	        return $now >= $earliestPromotion;
84	    }
