86	    /**
87	     * Compute the earliest timestamp at which full promotion is allowed.
88	     */
89	    public static function earliestPromotionAt(\DateTimeImmutable $canaryStartedAt): \DateTimeImmutable
90	    {
91	        return $canaryStartedAt->modify('+' . self::minPromotionHours() . ' hours');
92	    }
