3	namespace App\Jobs;
4	
5	use App\Application\Backup\BackupMetadataService;
6	use App\Application\Logging\StructuredLogger;
7	use App\Domain\Audit\Contracts\AuditEventRepositoryInterface;
8	use App\Domain\Audit\Enums\AuditAction;
9	use App\Infrastructure\Security\EncryptionService;
10	use Illuminate\Bus\Queueable;
11	use Illuminate\Contracts\Queue\ShouldQueue;
12	use Illuminate\Foundation\Bus\Dispatchable;
13	use Illuminate\Queue\InteractsWithQueue;
14	use Illuminate\Queue\SerializesModels;
15	use Illuminate\Support\Facades\DB;
16	use Illuminate\Support\Facades\Storage;
17	use Illuminate\Support\Str;
18	
19	/**
20	 * Orchestrates the daily local backup.
21	 *
22	 * This job:
23	 *   1. Creates a pending BackupJob record via BackupMetadataService
24	 *   2. Executes mysqldump and writes a compressed .sql.gz to storage/app/backups/
25	 *   3. Builds a manifest (dump path, table row-count summary, attachment inventory)
26	 *   4. Marks the job success/failed with manifest + size_bytes
27	 *   5. Records a BackupRun audit event
28	 *
29	 * The backup artifact is stored locally under storage/app/backups/ using the
30	 * naming convention: YYYY-MM-DD-{short-job-id}.sql.gz
31	 *
32	 * Database credentials are passed to mysqldump via a temporary options file
33	 * (never on the command line) to avoid exposure in process listings.
34	 */
35	class RunBackupJob implements ShouldQueue
36	{
37	    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
38	
39	    /** Resolved via handle() DI — stored here for use in private helpers. */
40	    private ?EncryptionService $encryption = null;
41	
42	    public function __construct(
43	        private readonly bool $isManual = false,
44	    ) {}
45	
46	    public function handle(
47	        BackupMetadataService $metadata,
48	        AuditEventRepositoryInterface $audit,
49	        StructuredLogger $logger,
50	        EncryptionService $encryption,
51	    ): void {
52	        // Store encryption service for use in private helpers (SerializesModels prevents constructor DI)
53	        $this->encryption = $encryption;
54	
55	        $job = $metadata->startBackup($this->isManual);
56	
57	        try {
58	            $metadata->markRunning($job->id);
59	            $logger->info('Backup started', ['job_id' => $job->id, 'is_manual' => $this->isManual], 'backup');
60	
61	            $dumpPath  = $this->executeDump($job->id);
62	            $manifest  = $this->buildManifest($dumpPath);
63	            $sizeBytes = $this->estimateSizeBytes($manifest);
64	
65	            $metadata->completeBackup($job->id, $manifest, $sizeBytes);
66	            $logger->info('Backup completed', [
67	                'job_id'     => $job->id,
68	                'size_bytes' => $sizeBytes,
69	                'tables'     => count($manifest['tables'] ?? []),
70	                'files'      => $manifest['attachment_file_count'] ?? 0,
71	            ], 'backup');
72	
73	            $audit->record(
74	                correlationId:  (string) Str::uuid(),
75	                action:         AuditAction::BackupRun,
76	                actorId:        null,
77	                auditableType:  'BackupJob',
78	                auditableId:    $job->id,
79	                beforeHash:     null,
80	                afterHash:      null,
81	                payload:        ['status' => 'success', 'size_bytes' => $sizeBytes, 'is_manual' => $this->isManual],
82	                ipAddress:      '127.0.0.1',
83	            );
84	        } catch (\Throwable $e) {
85	            $metadata->failBackup($job->id, $e->getMessage());
86	            $logger->error('Backup failed', ['job_id' => $job->id, 'error' => $e->getMessage()], 'backup');
87	
88	            $audit->record(
89	                correlationId:  (string) Str::uuid(),
90	                action:         AuditAction::BackupRun,
91	                actorId:        null,
92	                auditableType:  'BackupJob',
93	                auditableId:    $job->id,
94	                beforeHash:     null,
95	                afterHash:      null,
96	                payload:        ['status' => 'failed', 'error' => $e->getMessage()],
97	                ipAddress:      '127.0.0.1',
98	            );
99	
100	            throw $e;
101	        }
102	    }
103	
104	    // -------------------------------------------------------------------------
105	    // Database dump
106	    // -------------------------------------------------------------------------
107	
108	    /**
109	     * Execute mysqldump and write a gzip-compressed dump file to storage/app/backups/.
110	     *
111	     * Uses a temporary MySQL options file for credentials to avoid exposing the
112	     * password in process listings (ps, /proc/*/cmdline). The options file is
113	     * removed immediately after mysqldump completes regardless of outcome.
114	     *
115	     * @param string $jobId UUID of the BackupJob record (used in filename)
116	     * @return string        Absolute path to the created .sql.gz file
117	     *
118	     * @throws \RuntimeException If mysqldump exits with a non-zero code
119	     */
120	    private function executeDump(string $jobId): string
121	    {
122	        $dbHost     = config('database.connections.mysql.host', '127.0.0.1');
123	        $dbPort     = config('database.connections.mysql.port', 3306);
124	        $dbName     = config('database.connections.mysql.database');
125	        $dbUser     = config('database.connections.mysql.username');
126	        $dbPassword = config('database.connections.mysql.password', '');
127	
128	        $backupDir = Storage::disk('local')->path('backups');
129	        if (!is_dir($backupDir)) {
130	            mkdir($backupDir, 0755, true);
131	        }
132	
133	        $filename = date('Y-m-d') . '-' . substr($jobId, 0, 8) . '.sql.gz';
134	        $dumpPath = $backupDir . '/' . $filename;
135	
136	        // Write credentials to a temp options file (mode 0600 — owner-readable only)
137	        $optFile = tempnam(sys_get_temp_dir(), 'meridian_bk_');
138	        file_put_contents($optFile, implode("\n", [
139	            '[client]',
140	            'password=' . $dbPassword,
141	        ]));
142	        chmod($optFile, 0600);
143	
144	        try {
145	            $command = sprintf(
146	                'mysqldump --defaults-extra-file=%s --host=%s --port=%s --user=%s'
147	                . ' --single-transaction --routines --triggers --skip-lock-tables %s'
148	                . ' | gzip > %s',
149	                escapeshellarg($optFile),
150	                escapeshellarg((string) $dbHost),
151	                escapeshellarg((string) $dbPort),
152	                escapeshellarg((string) $dbUser),
153	                escapeshellarg((string) $dbName),
154	                escapeshellarg($dumpPath),
155	            );
156	
157	            $output     = [];
158	            $returnCode = 0;
159	            exec($command . ' 2>&1', $output, $returnCode);
160	
161	            if ($returnCode !== 0) {
162	                throw new \RuntimeException(
163	                    'mysqldump exited with code ' . $returnCode . ': ' . implode(' ', $output)
164	                );
165	            }
166	        } finally {
167	            @unlink($optFile);
168	        }
169	
170	        // HIGH-2: Encrypt the compressed dump file at rest.
171	        // Read the plaintext .sql.gz, encrypt it using AES-256-CBC via EncryptionService,
172	        // write the encrypted JSON envelope as .sql.gz.enc, then delete the plaintext artifact.
173	        $plaintext = file_get_contents($dumpPath);
174	        $envelope  = $this->encryption->encrypt($plaintext);
175	        $encPath   = $dumpPath . '.enc';
176	        file_put_contents($encPath, json_encode($envelope));
177	        @unlink($dumpPath);
178	
179	        return $encPath;
180	    }
181	
182	    // -------------------------------------------------------------------------
183	    // Manifest building
184	    // -------------------------------------------------------------------------
185	
186	    /**
187	     * Build the backup manifest.
188	     *
189	     * The manifest records:
190	     *   - dump_file: relative storage path to the .sql.gz artifact
191	     *   - dump_size_bytes: compressed dump file size in bytes
192	     *   - tables: array of {name, row_count} for all application tables
193	     *   - attachment_file_count: number of attachment files in storage
194	     *   - attachment_storage_bytes: total byte count in attachment storage
195	     *   - created_at: ISO-8601 timestamp of manifest creation
196	     *
197	     * @param string $dumpPath Absolute path to the .sql.gz file
198	     */
199	    private function buildManifest(string $dumpPath): array
200	    {
201	        $dumpSizeBytes = file_exists($dumpPath) ? filesize($dumpPath) : 0;
202	
203	        // Store only the filename (relative to the backups/ directory) in the manifest
204	        $dumpFilename = basename($dumpPath);
205	
206	        return [
207	            'created_at'               => now()->toIso8601String(),
208	            'dump_file'                => 'backups/' . $dumpFilename,
209	            'dump_size_bytes'          => $dumpSizeBytes,
210	            'tables'                   => $this->collectTableStats(),
211	            'attachment_file_count'    => $this->countAttachmentFiles(),
212	            'attachment_storage_bytes' => $this->sumAttachmentStorageBytes(),
213	        ];
214	    }
215	
216	    /**
217	     * Collect row counts for all application tables.
218	     */
219	    private function collectTableStats(): array
220	    {
221	        $tables = [
222	            'users', 'roles', 'departments', 'documents', 'document_versions',
223	            'attachments', 'attachment_links', 'audit_events', 'idempotency_keys',
224	            'configuration_sets', 'configuration_versions', 'canary_rollout_targets',
225	            'configuration_rules', 'workflow_templates', 'workflow_template_nodes',
226	            'workflow_instances', 'workflow_nodes', 'approvals', 'to_do_items',
227	            'document_number_sequences', 'sales_documents', 'sales_line_items',
228	            'returns', 'inventory_movements', 'backup_jobs', 'metrics_snapshots',
229	            'structured_logs', 'failed_login_attempts',
230	        ];
231	
232	        $stats = [];
233	        foreach ($tables as $table) {
234	            try {
235	                $count = DB::table($table)->count();
236	                $stats[] = ['table' => $table, 'row_count' => $count];
237	            } catch (\Throwable) {
238	                $stats[] = ['table' => $table, 'row_count' => null, 'error' => 'inaccessible'];
239	            }
240	        }
241	
242	        return $stats;
243	    }
244	
245	    /**
246	     * Count encrypted attachment files in local storage.
247	     */
248	    private function countAttachmentFiles(): int
249	    {
250	        try {
251	            $files = Storage::disk('local')->allFiles('attachments');
252	            return count($files);
253	        } catch (\Throwable) {
254	            return 0;
255	        }
256	    }
257	
258	    /**
259	     * Sum total bytes of attachment files in local storage.
260	     */
261	    private function sumAttachmentStorageBytes(): int
262	    {
263	        try {
264	            $files = Storage::disk('local')->allFiles('attachments');
265	            $total = 0;
266	            foreach ($files as $file) {
267	                $total += Storage::disk('local')->size($file);
268	            }
269	            return $total;
270	        } catch (\Throwable) {
271	            return 0;
272	        }
273	    }
274	
275	    /**
276	     * Compute total backup size in bytes: dump artifact + attachment files.
277	     */
278	    private function estimateSizeBytes(array $manifest): int
279	    {
280	        return (int) ($manifest['dump_size_bytes'] ?? 0)
281	             + (int) ($manifest['attachment_storage_bytes'] ?? 0);
282	    }
283	}
