8	    case Create     = 'create';
9	    case Update     = 'update';
10	    case Delete     = 'delete';
11	
12	    // Document operations
13	    case Archive    = 'archive';
14	    case Download   = 'download';
15	
16	    // Attachment operations
17	    case LinkCreate  = 'link_create';
18	    case LinkConsume = 'link_consume';
19	    case LinkRevoke  = 'link_revoke';
20	
21	    // Workflow operations
22	    case Approve    = 'approve';
23	    case Reject     = 'reject';
24	    case Reassign   = 'reassign';
25	    case AddApprover = 'add_approver';
26	    case Withdraw   = 'withdraw';
27	
28	    // Configuration operations
29	    case RolloutStart   = 'rollout_start';
30	    case RolloutPromote = 'rollout_promote';
31	    case RolloutBack    = 'rollout_back';
32	
33	    // Sales operations
34	    case SalesSubmit   = 'sales_submit';
35	    case SalesComplete = 'sales_complete';
36	    case SalesVoid     = 'sales_void';
37	    case ReturnCreate  = 'return_create';
38	    case ReturnComplete = 'return_complete';
39	
40	    // Authentication operations
41	    case Login       = 'login';
42	    case Logout      = 'logout';
43	    case LoginFailed = 'login_failed';
44	    case Lockout     = 'lockout';
45	    case PasswordChange = 'password_change';
46	
47	    // System operations
48	    case BackupRun   = 'backup_run';
49	
50	    /**
51	     * Whether this action involves a security-sensitive event.
52	     */
53	    public function isSecurityEvent(): bool
54	    {
55	        return match ($this) {
56	            self::Login, self::Logout, self::LoginFailed,
57	            self::Lockout, self::PasswordChange          => true,
