5	use App\Domain\Audit\Contracts\AuditEventRepositoryInterface;
6	use App\Domain\Audit\Enums\AuditAction;
7	use App\Models\AuditEvent;
8	
9	class EloquentAuditEventRepository implements AuditEventRepositoryInterface
10	{
11	    /**
12	     * Record an audit event.
13	     *
14	     * Idempotency: If a record with the given correlation_id already exists,
15	     * the existing record is returned without creating a duplicate.
16	     *
17	     * CRITICAL: This repository NEVER calls update() or delete().
18	     * The AuditEvent model itself enforces this at the model level as well.
19	     */
20	    public function record(
21	        string $correlationId,
22	        AuditAction $action,
23	        ?string $actorId,
24	        ?string $auditableType,
25	        ?string $auditableId,
26	        ?string $beforeHash,
27	        ?string $afterHash,
28	        array $payload,
29	        string $ipAddress
30	    ): mixed {
31	        // Compliance guard: modification actions must always carry an afterHash.
32	        if ($action->isModification() && $afterHash === null) {
33	            throw new \InvalidArgumentException(
34	                "afterHash must not be null for modification action [{$action->value}]"
35	            );
36	        }
37	
38	        // Idempotency check — return existing record without inserting a duplicate.
39	        if ($this->correlationIdExists($correlationId)) {
40	            return AuditEvent::where('correlation_id', $correlationId)->first();
41	        }
42	
43	        $event = new AuditEvent();
44	        $event->correlation_id  = $correlationId;
45	        $event->action          = $action;
46	        $event->actor_id        = $actorId;
47	        $event->auditable_type  = $auditableType;
48	        $event->auditable_id    = $auditableId;
49	        $event->before_hash     = $beforeHash;
50	        $event->after_hash      = $afterHash;
51	        $event->payload         = $payload;
52	        $event->ip_address      = $ipAddress;
53	        $event->created_at      = now();
54	
55	        // save() is overridden on AuditEvent to throw if $this->exists — safe here
56	        // because this is a new (non-persisted) model instance.
57	        $event->save();
58	
59	        return $event;
60	    }
61	
62	    /**
63	     * Whether an audit event with the given correlation_id already exists.
64	     */
65	    public function correlationIdExists(string $correlationId): bool
66	    {
67	        return AuditEvent::where('correlation_id', $correlationId)->exists();
68	    }
